import{_ as e,o as l,c as i,ag as t}from"./chunks/framework.D--JA8_b.js";const o="/caesar-blog/images/%E5%B7%A5%E5%85%B7.jpg",r="/caesar-blog/images/%E6%97%A7%E6%89%8B%E6%9C%BA%E7%94%B5%E6%B1%A0.jpg",_=JSON.parse('{"title":"小米14魔改电池更换实录","description":"","frontmatter":{},"headers":[],"relativePath":"posts/2026-04-20-replace-mobile-phone-battery.md","filePath":"posts/2026-04-20-replace-mobile-phone-battery.md","lastUpdated":1776700038000}'),h={name:"posts/2026-04-20-replace-mobile-phone-battery.md"};function s(p,a,n,c,d,m){return l(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="小米14魔改电池更换实录" tabindex="-1">小米14魔改电池更换实录 <a class="header-anchor" href="#小米14魔改电池更换实录" aria-label="Permalink to &quot;小米14魔改电池更换实录&quot;">​</a></h1><p>发布时间：2026-04-20 · 标签：#小米14 #魔改电池 #DIY #换电池</p><hr><p>我的小米14已经使用了两年半，电池衰减严重，现在每天需要充三次电。即使有快充，频繁充电还是挺影响使用体验的。</p><h2 id="从官方到魔改" tabindex="-1">从官方到魔改 <a class="header-anchor" href="#从官方到魔改" aria-label="Permalink to &quot;从官方到魔改&quot;">​</a></h2><p>本来我已经预约了小米官方的换电池服务，但想到魔改电池容量大了500mAh，续航会有明显提升，而且自己动手换也挺有乐趣的。评估了一下自己的动手能力，觉得没问题，就决定自己干！</p><h2 id="准备工具" tabindex="-1">准备工具 <a class="header-anchor" href="#准备工具" aria-label="Permalink to &quot;准备工具&quot;">​</a></h2><p>为了这次换电池，我买了一套工具：</p><ul><li>精密螺丝刀套装</li><li>电动除胶机</li><li>酒精</li><li>开后盖的薄塑料片</li><li>摄像头防护贴</li><li>魔改电池（容量比原装大500mAh）</li><li>手机壳边框背胶</li></ul><p><img src="'+o+'" alt="工具全家福"></p><h2 id="更换过程" tabindex="-1">更换过程 <a class="header-anchor" href="#更换过程" aria-label="Permalink to &quot;更换过程&quot;">​</a></h2><p>从动手到结束，一共花了不到一个小时，比想象中顺利。</p><h3 id="开后盖" tabindex="-1">开后盖 <a class="header-anchor" href="#开后盖" aria-label="Permalink to &quot;开后盖&quot;">​</a></h3><ol><li>用电吹风对着后盖吹了30秒，让胶软化</li><li>用飞鹰的金属刀片先插一条缝出来</li><li>把薄塑料片划进去，慢慢扩大缝隙</li><li>胶多的地方滴一些酒精，很快就开了</li></ol><p>小米14的后盖还挺好开的，比想象中简单。</p><h3 id="换电池" tabindex="-1">换电池 <a class="header-anchor" href="#换电池" aria-label="Permalink to &quot;换电池&quot;">​</a></h3><ol><li>小米14一共有10个螺丝，其中一个是短螺丝，注意位置别搞混</li><li>按照&quot;拆2拆1装1装2&quot;的顺序操作</li><li>用除胶机清除后盖的旧胶，三五分钟就清干净了，比手动清理省力多了</li></ol><h3 id="新电池" tabindex="-1">新电池 <a class="header-anchor" href="#新电池" aria-label="Permalink to &quot;新电池&quot;">​</a></h3><p><img src="'+r+'" alt="魔改电池"></p><h2 id="使用效果" tabindex="-1">使用效果 <a class="header-anchor" href="#使用效果" aria-label="Permalink to &quot;使用效果&quot;">​</a></h2><p>换好以后，快充完全正常，没有任何问题。使用时间上，感觉比旧电池好很多。而且魔改电池有10%的容量是放着备用的，这样电池寿命理论上也会好很多。</p><p>总的来说，这次DIY换电池还是很成功的，既省了钱，又提升了续航，还体验了动手的乐趣！</p><hr><p><em>本文使用 Claude Code 智能助手协助撰写</em></p>',24)])])}const b=e(h,[["render",s]]);export{_ as __pageData,b as default};
